module RefModule(clk, reset, enable, data, q);

    input clk;
    input reset;
    input enable;
    input [7:0] data;
    output [7:0] q;
    reg [7:0] q;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt)
        begin
            if (reset)
                q <= 0;
            else if (enable)
                q <= data;
        end

endmodule
